```javascript
// Minimal CAPA data model
const CAPA_STATES = {
  NEW: 'new',
  INVESTIGATING: 'investigating',
  ROOT_CAUSE_IDENTIFIED: 'root_cause_identified',
  REMEDIATION_PLANNED: 'remediation_planned',
  IN_REMEDIATION: 'in_remediation',
  VERIFIED: 'verified',
  CLOSED: 'closed'
};

class CAPA {
  constructor(data) {
    this.id = data.id;
    this.title = data.title;
    this.severity = data.severity;
    this.state = CAPA_STATES.NEW;
    this.evidence = data.evidence || [];
    this.headers = data.headers || [];
    this.tenants = data.tenants || [];
    this.logs = data.logs || [];
    this.traces = data.traces || [];
    this.region = data.region;
    this.createdAt = new Date();
  }

  transition(newState) {
    const validTransitions = {
      [CAPA_STATES.NEW]: [CAPA_STATES.INVESTIGATING],
      [CAPA_STATES.INVESTIGATING]: [CAPA_STATES.ROOT_CAUSE_IDENTIFIED, CAPA_STATES.CLOSED],
      [CAPA_STATES.ROOT_CAUSE_IDENTIFIED]: [CAPA_STATES.REMEDIATION_PLANNED],
      [CAPA_STATES.REMEDIATION_PLANNED]: [CAPA_STATES.IN_REMEDIATION],
      [CAPA_STATES.IN_REMEDIATION]: [CAPA_STATES.VERIFIED],
      [CAPA_STATES.VERIFIED]: [CAPA_STATES.CLOSED],
      [CAPA_STATES.CLOSED]: []
    };

    if (validTransitions[this.state].includes(newState)) {
      this.state = newState;
      return true;
    }
    return false;
  }
}
```

