  "evidence": [
    { "type": "string", "url": "string", "uploaded_at": "timestamp" }
  ],
  "containment_confirmed": "boolean",
  "root_cause": "string",
  "corrective_action": "string",
  "preventive_action": "string",
  "status": "enum",
  "created_at": "timestamp",
  "updated_at": "timestamp"
}
