## Canary-Based Preventive Action Rollout

```javascript
async function rolloutPreventiveAction(capa_id, action) {
  const capa = await db.capas.findById(capa_id);
  const canary_tenants = await db.tenants.find({ 
    size: 'small', 
    opted_in: true, 
    limit: 5 
  });

  // Phase 1: Canary deployment
  console.log(`Rolling out to ${canary_tenants.length} canary tenants...`);
  for (const tenant of canary_tenants) {
    await applyAction(tenant.id, action);
    await monitor(tenant.id, { duration: '1h', metrics: ['error_rate', 'latency'] });
  }

  const canary_ok = await validateCanaryMetrics(canary_tenants);
  if (!canary_ok) {
    console.error('Canary validation failed, rolling back...');
    await rollback(action);
    throw new Error('Canary deployment failed');
  }

  // Phase 2: Staged rollout (10% → 50% → 100%)
  for (const pct of [10, 50, 100]) {
    const batch = await db.tenants.getBatch({ percentage: pct, exclude: canary_tenants });
    await applyAction(batch, action);
    await monitor(batch, { duration: '2h', metrics: ['error_rate', 'latency', 'user_reports'] });
