## Code Example
```javascript
// CAPA State Machine Implementation
class CAPAStateMachine {
  constructor(region, dependency) {
    this.region = region;
    this.dependency = dependency;
    this.currentState = 'pending';
  }

  transition(newState, context) {
    const validTransitions = {
      pending: ['triage'],
      triage: ['containment', 'escalation'],
      containment: ['investigation'],
      investigation: ['remediation'],
      remediation: ['verification'],
      verification: ['closed']
    };

    if (validTransitions[this.currentState]?.includes(newState)) {
      this.currentState = newState;
      this.logTransition(newState, context);
    }
  }

  logTransition(newState, context) {
    // Log to region-specific telemetry system
    console.log(`${this.region}: CAPA transitioned to ${newState}`, context);
  }
}
```
